import { writeOutput } from "./codegen";

const DOCS_URL = "https://www.plain.com/docs/graphql/introduction";
const PLACEHOLDER_VALUE =
  "plainApiKey__CoffeeSafeLocalCoffeeSafeLocalCoffeeSafeLo";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Plain.com GraphQL API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:plain",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../contracts/firewalls";',
    "",
    "export const plainFirewall = {",
    '  name: "plain",',
    '  description: "Plain",',
    "  placeholders: {",
    `    PLAIN_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://core-api.uk.plain.com",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.PLAIN_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Plain firewall config...");
  const ts = generateTypeScript();
  writeOutput("plain", ts, import.meta.dirname);
}
